      "tab_order_heading": "Tab order",
      "fakes_heading": "⚠ Fake buttons",
      "fakes_help": "Elements with cursor:pointer that look clickable but cannot be reached by keyboard. Common cause: a div with onClick instead of a real <button>. Fix: convert to <button>, OR add tabindex=\"0\" + role=\"button\" + keyboard event handlers.",
      "pos_heading": "⚠ Positive tabindex",
      "pos_help": "Elements with tabindex > 0 break natural document tab order and confuse keyboard users. Fix: use tabindex=\"0\" (default order) or rely on default focusability for buttons/links.",
      "no_label_heading": "🔴 Missing accessible names",
      "no_label_help": "Focusable elements without text, aria-label, aria-labelledby, or title. Screen reader users would hear only the tag name, e.g., \"button\" with no context. Fix: add aria-label or visible text.",
